import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecurePathTraversalExample {

    public static void main(String[] args) throws IOException {
        String userInput = "../secret.txt";
        String directory = "/var/www/html/files/";

        // Prevent path traversal by resolving the input path against the base directory
        Path basePath = Paths.get(directory).normalize();
        Path resolvedPath = basePath.resolve(userInput).normalize();

        // Check if the resolved path is within the base directory
        if (!resolvedPath.startsWith(basePath)) {
            System.out.println("Invalid path specified");
            return;
        }

        byte[] fileContent = Files.readAllBytes(resolvedPath);
        System.out.println(new String(fileContent));
    }
}

